import '../lib/license_gate.dart';
import '../lib/scan_report_adapter.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  const upgradedPayload = r'''
{
  "document": {
    "artifacts": [
      {
        "coordinates": {"name": "render-core", "version": "4.2.0"},
        "license": {"expression": "MIT OR Apache-2.0"},
        "scope": "runtime"
      }
    ]
  }
}
''';

  final records = ScanReportAdapter().decode(upgradedPayload);
  check(records.length == 1, 'reads artifacts from upgraded reports');
  check(records.single.name == 'render-core', 'reads nested coordinates');
  check(
    records.single.licenseExpression == 'MIT OR Apache-2.0',
    'reads the dependency license expression',
  );
  check(records.single.runtime, 'maps the upgraded runtime scope');

  final alternative = DependencyRecord(
    name: 'render-core',
    version: '4.2.0',
    licenseExpression: 'MIT OR Apache-2.0',
    runtime: true,
  );
  check(
    LicenseGate(<String>{
      'Apache-2.0',
    }).violations(<DependencyRecord>[alternative]).isEmpty,
    'an allowed alternative satisfies a compound expression',
  );

  print('feedback tests passed');
}
